var NEW_HEARING_VENUE_TMP_PATH = "/ds/var/page/Tmp/TransCourt";
	
//--------------------------------------- 	TransCourt_Popup  ---------------------------------------
function TransCourt_Popup(){}
	
TransCourt_Popup.firstFocusedAdaptorId = function() {
	return 'TransCourt_VenueCode'; }
	
TransCourt_Popup.nextFocusedAdaptorId = function() {
	return 'TransCourt_VenueLOVBtn'; }
			
TransCourt_Popup.lower = {
	eventBinding: {
		singleClicks: [ {element: "TransCourt_CancelBtn"} ],
		keys: [ { key: Key.F4, element: "TransCourt_Popup" } ]
	}
};
				
//--------------------------------------  TransCourtCode  -------------------------------------------
function TransCourtCode(){}
TransCourtCode.dataBinding = "/ds/EnterVariableData/FastTrack/transCourtCode";
TransCourtCode.isReadOnly = function(){ return true; }
//TransCourtCode.tabIndex = __tabIdx++;
TransCourtCode.maxLength = 3;
TransCourtCode.helpText = "Unique LCD three digit court location code – list available";
TransCourtCode.mandatoryOn = [TransCourtName.dataBinding];
TransCourtCode.isMandatory = function() { return TransCourtName.isMandatory(); }
TransCourtCode.logicOn = [TransCourtCode.dataBinding];
TransCourtCode.logic = function() {   
	var code = Services.getValue(TransCourtCode.dataBinding);		     		
   	var xpathName = REF_DATA_XPATH + "/Courts/Court[./Code = " + TransCourtCode.dataBinding + "]/Name";	 
 	var venueName = Services.getValue(xpathName); 	 	 	
    Services.setValue(TransCourtName.dataBinding, venueName); }
TransCourtCode.enableOn = [TransCourtName.dataBinding];
TransCourtCode.isEnabled = function() {
	var isEbld = TransCourtName.isEnabled(); 		
	return isEbld; }

function TransCourtLOVBtn() {}
TransCourtLOVBtn.actionBinding = function()  {
	Services.dispatchEvent("TransCourt_Popup", PopupGUIAdaptor.EVENT_RAISE); 
	var venueCode = Services.getValue(TransCourtCode.dataBinding);
	Services.setValue(TransCourt_VenueCode.dataBinding, venueCode); }
TransCourtLOVBtn.tabIndex = __tabIdx++;
TransCourtLOVBtn.enableOn = [TransCourtName.dataBinding];
TransCourtLOVBtn.isEnabled = function() {
	var isEbld = TransCourtName.isEnabled();		
	return isEbld; }
TransCourtLOVBtn.additionalBindings = {
	eventBinding: {
		keys: [ { key: Key.F6, element: "TransCourtCode" }, { key: Key.F6, element: "TransCourtName" } ]
	}
};

function TransCourt_VenueCode(){}
TransCourt_VenueCode.dataBinding = "/ds/EnterVariableData/FastTrack/transCourt_VenueCode";
TransCourt_VenueCode.helpText = "Unique three digit court location code - list available.";
TransCourt_VenueCode.maxLength = 3;
TransCourt_VenueCode.logicOn = [TransCourt_VenueCode.dataBinding];
TransCourt_VenueCode.logic = function() {	
	var code = Services.getValue(TransCourt_VenueCode.dataBinding);
	var xpathName = REF_DATA_XPATH + "/Courts/Court[./Code = " + TransCourt_VenueCode.dataBinding + "]/Name";	
	var venueName = Services.getValue(xpathName);
	if(venueName != null && venueName != "") {
		Services.setValue(TransCourt_VenueName.dataBinding, code);		
		Services.setValue(TransCourtCourtsLOVGrid.dataBinding, code); }
	else {
		Services.setValue(TransCourt_VenueCode.dataBinding, "");
		Services.setValue(TransCourt_VenueName.dataBinding, "");
		Services.setValue(TransCourtCourtsLOVGrid.dataBinding, "");	} }

function TransCourt_VenueName(){}
TransCourt_VenueName.dataBinding = "/ds/EnterVariableData/FastTrack/transCourt_VenueName";
//TransCourt_VenueName.tabIndex = __tabIdx++;
TransCourt_VenueName.isReadOnly = function(){ return false; }
TransCourt_VenueName.isTemporary = function(){ return true; }
TransCourt_VenueName.maxLength = 30;
TransCourt_VenueName.helpText = "Name of the Court.";
TransCourt_VenueName.isMandatory = function(){ return true; }
TransCourt_VenueName.validate = function(){ return null; }
TransCourt_VenueName.srcData = REF_DATA_XPATH + "/Courts";
TransCourt_VenueName.rowXPath = "Court";
TransCourt_VenueName.keyXPath = "Code";
TransCourt_VenueName.displayXPath = "Name";
TransCourt_VenueName.logicOn  = [TransCourt_VenueName.dataBinding];
TransCourt_VenueName.logic = function() {
	var codeOrName = Services.getValue(TransCourt_VenueName.dataBinding);      
	var xpath = REF_DATA_XPATH + "/Courts/Court[Code = " + TransCourt_VenueName.dataBinding + "]/Code";
	var code = Services.getValue(xpath);
	if(code == null || "" == code) {
		var name = Services.getValue(TransCourt_VenueName.dataBinding);     
		code = Services.getValue(REF_DATA_XPATH + "/Courts/Court[Name = " + TransCourt_VenueName.dataBinding + "]/Code");  }
	if( code != null && code != "") { 	
		Services.setValue(TransCourt_VenueCode.dataBinding, code); }
	else { 
		Services.setValue(TransCourt_VenueName.dataBinding, "");
		Services.setValue(TransCourt_VenueCode.dataBinding, "");
		Services.setValue(TransCourt_ContactDetails_Address_Line1.dataBinding, "");
		Services.setValue(TransCourt_ContactDetails_Address_Line2.dataBinding, "");
		Services.setValue(TransCourt_ContactDetails_Address_Line3.dataBinding, "");
		Services.setValue(TransCourt_ContactDetails_Address_Line4.dataBinding, "");
		Services.setValue(TransCourt_ContactDetails_Address_Line5.dataBinding, "");
		Services.setValue(TransCourt_ContactDetails_Address_Postcode.dataBinding, "");
		Services.setValue(TransCourt_ContactDetails_Address_DXNumber.dataBinding, "");
		Services.setValue(TransCourt_ContactDetails_Address_TelephoneNumber.dataBinding, "");
		Services.setValue(TransCourt_ContactDetails_Address_FaxNumber.dataBinding, "");
		Services.setValue(TransCourt_Address_Grid.dataBinding, "");	} }

