//------------------------------------  TransCourtCourtsLOVGrid  ----------------------------------------------
function TransCourtCourtsLOVGrid() {};
TransCourtCourtsLOVGrid.dataBinding = "/ds/var/page/SelectedLOVRow/OwningCourt";
TransCourtCourtsLOVGrid.srcData = REF_DATA_XPATH + "/Courts";
TransCourtCourtsLOVGrid.rowXPath = "Court";
TransCourtCourtsLOVGrid.keyXPath = "Code";
TransCourtCourtsLOVGrid.columns = [	{xpath: "Code"}, {xpath: "Name"} ];
TransCourtCourtsLOVGrid.logicOn = [TransCourtCourtsLOVGrid.dataBinding];
TransCourtCourtsLOVGrid.logic = function() {
	var id = Services.getValue(TransCourtCourtsLOVGrid.dataBinding);
	Services.setValue(TransCourt_VenueCode.dataBinding, id);
	Services.setValue(TransCourt_VenueName.dataBinding, id); } 

//--------------------------------	TransCourt_Address_Grid --------------------------------------------
function TransCourt_Address_Grid(){};
TransCourt_Address_Grid.dataBinding = "/ds/var/page/SelectedGridRow/SelectedAddress"; 
TransCourt_Address_Grid.srcData = REF_DATA_XPATH + "/Courts/Court[Code = " + TransCourtCourtsLOVGrid.dataBinding + "]/ContactDetails"; 
TransCourt_Address_Grid.rowXPath = "Address";		// Individual Court/venue
TransCourt_Address_Grid.keyXPath = "AddressId";  	// Unique identifier for a Court/venue
TransCourt_Address_Grid.columns = [   				// column bindings
	{xpath: "Line[1]", sort: function(a,b){if(a < b){return 1;};if(a > b){return -1;};return 0;}},
	{xpath: "Line[2]", sort: function(a,b){if(a < b){return 1;};if(a > b){return -1;};return 0;}} ];

TransCourt_Address_Grid.retrieveOn = [TransCourtCourtsLOVGrid.dataBinding];
TransCourt_Address_Grid.srcDataOn = [TransCourtCourtsLOVGrid.dataBinding];

TransCourt_Address_Grid.logicOn = [TransCourt_Address_Grid.dataBinding,	TransCourtCourtsLOVGrid.dataBinding];
TransCourt_Address_Grid.logic = function() {
	var courtId = Services.getValue(TransCourtCourtsLOVGrid.dataBinding);
	var addressId = Services.getValue(TransCourt_Address_Grid.dataBinding);
	if (courtId != null && addressId != null && "" != courtId && "" != addressId){
		var b11 = REF_DATA_XPATH + "/Courts/Court[Code = ";
		var b13 = "]/ContactDetails/";
		var b12 = b13 + "Address[./AddressId = ";
		var xpathAdd1 = b11+courtId+b12+addressId+"]/Line[1]";	
		var xpathAdd2 = b11+courtId+b12+addressId+"]/Line[2]";	
		var xpathAdd3 = b11+courtId+b12+addressId+"]/Line[3]";	
		var xpathAdd4 = b11+courtId+b12+addressId+"]/Line[4]";	
		var xpathAdd5 = b11+courtId+b12+addressId+"]/Line[5]";	
		var xpathPostcode = b11+courtId+b12+addressId+"]/PostCode";	
		var xpathDXNo  = b11+courtId+b13+"DX";	
		var xpathTelNo = b11+courtId+b13+"TelephoneNumber";	
		var xpathFaxNo = b11+courtId+b13+"FaxNumber";	
		var add1 = Services.getValue(xpathAdd1);
		var add2 = Services.getValue(xpathAdd2);
		var add3 = Services.getValue(xpathAdd3); 	if(add3==null) add3="";	
		var add4 = Services.getValue(xpathAdd4); 	if(add4==null) add4="";
		var add5 = Services.getValue(xpathAdd5); 	if(add5==null) add5="";
		var postcode = Services.getValue(xpathPostcode);		
		var dxNo = Services.getValue(xpathDXNo); 	if(dxNo==null)  dxNo="";
		var telNo = Services.getValue(xpathTelNo);	if(telNo==null) telNo="";
		var faxNo = Services.getValue(xpathFaxNo);	if(faxNo==null) faxNo="";
		Services.setValue(TransCourt_ContactDetails_Address_Line1.dataBinding, add1);
		Services.setValue(TransCourt_ContactDetails_Address_Line2.dataBinding, add2);
		Services.setValue(TransCourt_ContactDetails_Address_Line3.dataBinding, add3);
		Services.setValue(TransCourt_ContactDetails_Address_Line4.dataBinding, add4);
		Services.setValue(TransCourt_ContactDetails_Address_Line5.dataBinding, add5);
		Services.setValue(TransCourt_ContactDetails_Address_Postcode.dataBinding, postcode);		
		Services.setValue(TransCourt_ContactDetails_Address_DXNumber.dataBinding, dxNo);
		Services.setValue(TransCourt_ContactDetails_Address_TelephoneNumber.dataBinding, telNo);
		Services.setValue(TransCourt_ContactDetails_Address_FaxNumber.dataBinding, faxNo); } } 

function setHomeCrtDetails() {			   				   	
	var hcrtcode  =  WPU.getHomeCourtCode();		   
	var addxpath = REF_DATA_XPATH + "/Courts/Court[./Code='"+hcrtcode+"']/ContactDetails/Address"; 
	var xpathName = REF_DATA_XPATH + "/Courts/Court[./Code='"+hcrtcode+"']/Name";		   	 			   	 
	Services.setValue(TransCourtCode.dataBinding, hcrtcode);
	Services.setValue(TransCourt_VenueCode.dataBinding, hcrtcode);
	Services.setValue( TransCourtName.dataBinding, Services.getValue(xpathName));	
	var addAr = Services.getNodes( addxpath );
   	if( null != addAr && addAr.length == 1 )  {				   	 	
   		var ln1 = Services.getValue(addxpath+"/Line[1]");
   	 	var ln2 = Services.getValue(addxpath+"/Line[2]");
   	 	var ln3 = Services.getValue(addxpath+"/Line[3]");
   	 	var ln4 = Services.getValue(addxpath+"/Line[4]");
   	 	var ln5 = Services.getValue(addxpath+"/Line[5]");
   	 	var pcode = Services.getValue( addxpath+"/PostCode");
   	 	Services.setValue(TransAdLine1.dataBinding, ln1);
	 	Services.setValue(TransAdLine2.dataBinding, ln2);
	 	Services.setValue(TransAdLine3.dataBinding, ln3);
	 	Services.setValue(TransAdLine4.dataBinding, ln4);
	 	Services.setValue(TransAdLine5.dataBinding, ln5);
	 	Services.setValue(TransPostcode.dataBinding, pcode); } }	

/**  PostBuildX 15a: Can only bind once all elements declared, that's why this code his here, and not above **/
TransCourtCourtsLOVGrid.raise = {
	eventBinding: {
		singleClicks: [ {element: "TransCourt_VenueLOVBtn"} ],
		keys: [ { key: Key.F6, element: "TransCourt_VenueCode" }, { key: Key.F6, element: "TransCourt_VenueName" } ] } };	
	
//-------------------------------------  TransCourt_OKBtn  ------------------------------------------
function TransCourt_OKBtn(){}
TransCourt_OKBtn.tabIndex = __tabIdx++;
TransCourt_OKBtn.actionBinding = function() {		
	var venueCode = Services.getValue(TransCourt_VenueCode.dataBinding);
	var venueName = Services.getValue(TransCourt_VenueName.dataBinding);
 	var xpathName = REF_DATA_XPATH + "/Courts/Court[./Code = " + TransCourt_VenueName.dataBinding + "]/Name";	 
 	var checkVenueName = Services.getValue(xpathName);
 	if( null != checkVenueName && checkVenueName.length > 0) {  
 		/**value of checkVenueName is actually a code  - replace code with venuename **/
   		venueName = checkVenueName;	}
	Services.setValue(TransCourtCode.dataBinding, venueCode);
	if (null != TransAdLine1) {
		Services.setValue(TransAdLine1.dataBinding,  Services.getValue(TransCourt_ContactDetails_Address_Line1.dataBinding));
		Services.setValue(TransAdLine2.dataBinding,  Services.getValue(TransCourt_ContactDetails_Address_Line2.dataBinding));
		Services.setValue(TransAdLine3.dataBinding,  Services.getValue(TransCourt_ContactDetails_Address_Line3.dataBinding));
		Services.setValue(TransAdLine4.dataBinding,  Services.getValue(TransCourt_ContactDetails_Address_Line4.dataBinding));
		Services.setValue(TransAdLine5.dataBinding,  Services.getValue(TransCourt_ContactDetails_Address_Line5.dataBinding));
		Services.setValue(TransPostcode.dataBinding, Services.getValue(TransCourt_ContactDetails_Address_Postcode.dataBinding)); }		
	Services.setValue(TransCourtName.dataBinding, venueName);			
	FormController.getInstance().hideFormExtensionPopup("TransCourt"); }

TransCourt_OKBtn.enableOn = [NEW_HEARING_VENUE_TMP_PATH + "/Address/Line[1]"];

TransCourt_OKBtn.isEnabled = function() {	
	var c = Services.getValue(NEW_HEARING_VENUE_TMP_PATH + "/Address/Line[1]");
	if(c != null && c!= "") { return true; }
	else { return false; } }
//-------------------------------------  TransCourt_CancelBtn  --------------------------------------	
function TransCourt_CancelBtn(){}
TransCourt_CancelBtn.tabIndex = __tabIdx++;

